sql:
SELECT SUM(weight) 
FROM luggage 
WHERE passenger_id = 1 AND is_stowed = 1;

external_knowledge:
- Total passengers refer to the count of unique individuals on the flight;
- Total boardings indicate the number of times passengers have boarded the aircraft during the flight period;
- Total boarding passes represent the number of boarding passes issued for the respective flights.

sql:
SELECT AVG(walking_speed) 
FROM passenger_status 
WHERE is_seated = 1 AND has_stowed_luggage = 1;

SELECT p.passenger_id, p.first_name, p.last_name, lp.program_name
FROM passengers p
JOIN loyalty_programs lp ON p.loyalty_program_id = lp.program_id;

SELECT AVG(walking_speed) AS average_walking_speed
FROM passenger_status
WHERE is_seated = 1;

SELECT boarding_id, boarding_gate, qr_code
FROM boarding_passes
WHERE boarding_time < '2022-12-31 23:59:59';
